-- 参会人tab界面显示医生的abcd级别(添加text_1字段中显示)
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`, `version`) VALUES ('a8da3e74-d8b3-40d6-9528-8637ce0778ba', '66036d1a-4643-49d5-b21a-0db9d60b0563', '选择医生参会人时带入医生产品分级', '选择医生参会人时带入医生产品分级', 'trigger', 'from orionbase.common import models\nimport datetime\nfrom django.db import connection\nfrom django.utils import timezone\n\nif instance:\n    profession_id = instance.account_id\n    if profession_id:\n        remark = \'\'\n        yearmonth = timezone.localtime(timezone.now()).strftime(\'%Y-%m\')\n        with connection.cursor() as cursor:\n            sql_str = \"\"\"select b.name,c.label,d.label,f.name from product_metrics a left join products b on a.product_id=b.id \n                        left join picklist_values c on a.evaluation_id=c.id left join picklist_values d on a.picklist_1=d.id\n                        inner join metrics_versions f on a.version_id=f.id \n                        where a.deleted=0 and professional_id={0} and f.name=\'{1}\'; \"\"\"\n            \n            cursor.execute(sql_str.format(profession_id,yearmonth))\n            metrices = cursor.fetchone()\n            if metrices:\n                remark = u\"EGFR适应症: %s, T790M适应症: %s\" %(metrices[1] if metrices[1] else u\'未分级\', metrices[2] if metrices[2] else u\'未分级\')\n            else:\n                remark = u\"该医生未分级\"\n        if remark !=\'\':\n            instance.text_1 = remark', '', '0', '1', '2019-06-24 11:08:42', '1', '2020-10-20 11:23:12', 'pre_save', '1', 'custom', 'choose_event_account_with_metrices', '1');

