UPDATE `custom_settings` SET `value` = '\"{% with \\\"\\\" as states_show_attendee_expense_check_in %}\\n    [\\n    {% if this|is_model:\\\"EventAccounts\\\" %}\\n        {\\\"label\\\":\\\"\\u59d3\\u540d\\\", \\\"value\\\":\\\"{{this.account.name}}\\\"}, {\\\"label\\\":\\\"\\u79d1\\u5ba4\\\", \\\"value\\\":\\\"{{this.account.standard_department.label}}\\\"}, {\\\"label\\\":\\\"\\u533b\\u9662\\\", \\\"value\\\":\\\"{{this.account.hospital.name}}\\\"}, {\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u7ea7\\u522b\\\", \\\"value\\\":\\\"{{this.text_1}}\\\"}\\n    {% elif this|is_model:\\\"Contacts\\\" %}\\n        {\\\"label\\\":\\\"\\u59d3\\u540d\\\", \\\"value\\\":\\\"{{this.name}}\\\"}, {\\\"label\\\":\\\"\\u8054\\u7cfb\\u65b9\\u5f0f\\\", \\\"value\\\":\\\"{{this.telephone | default_if_none:\\\"\\\"}}\\\"}, {\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u8eab\\u4efd\\\", \\\"value\\\":\\\"{{this.description | default_if_none:\\\"\\\"}}\\\"},\\n        {\\\"label\\\":\\\"\\u5355\\u4f4d\\\", \\\"value\\\":\\\"{{this.company | default_if_none:\\\"\\\"}}\\\"}, {\\\"label\\\":\\\"\\u884c\\u653f\\u804c\\u52a1\\\", \\\"value\\\":\\\"{{this.administrator_title | default_if_none:\\\"\\\"}}\\\"}\\n    {% elif this|is_model:\\\"EventProfessionals\\\" %}\\n        {\\\"label\\\":\\\"\\u59d3\\u540d\\\", \\\"value\\\":\\\"{{this.name}}\\\"}, {\\\"label\\\":\\\"\\u79d1\\u5ba4\\\", \\\"value\\\":\\\"{{this.standard_department.label}}\\\"}, {\\\"label\\\":\\\"\\u533b\\u9662\\\", \\\"value\\\":\\\"{{this.hospital.name}}\\\"}\\n    {% endif %}\\n    {% if this.event.state.name in states_show_attendee_expense_check_in.split %}\\n        {% if this|is_model:\\\"EventAccounts\\\" %}\\n            ,{\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u5c5e\\u6027\\\",\\\"value\\\":\\\"\\u5728\\u5e93\\u533b\\u751f\\u53c2\\u4f1a\\u4eba\\\"},\\n        {% elif this|is_model:\\\"Contacts\\\" %}\\n            ,{\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u5c5e\\u6027\\\",\\\"value\\\":\\\"\\u975e\\u5728\\u5e93\\u975e\\u533b\\u751f\\u53c2\\u4f1a\\u4eba\\\"},\\n        {% elif this|is_model:\\\"EventProfessionals\\\" %}\\n            ,{\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u5c5e\\u6027\\\",\\\"value\\\":\\\"\\u975e\\u5728\\u5e93\\u533b\\u751f\\u53c2\\u4f1a\\u4eba\\\"},\\n        {% endif %}\\n        {% if this.own_expense %}\\n            {\\\"label\\\":\\\"\\u8d39\\u7528\\u627f\\u62c5\\u65b9\\u4fe1\\u606f\\\",\\\"value\\\":\\\"\\u81ea\\u62c5\\u8d39\\u7528\\\"},\\n        {% else %}{\\\"label\\\":\\\"\\u8d39\\u7528\\u627f\\u62c5\\u65b9\\u4fe1\\u606f\\\",\\\"value\\\":\\\"\\u975e\\u81ea\\u62c5\\u8d39\\u7528\\\"},\\n        {% endif %}\\n\\n        {% if this.check_in_type == \\\"check_in\\\" or this.check_in_type == \\\"walk_in\\\" %}\\n            {\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u7b7e\\u5230\\u60c5\\u51b5\\\",\\\"value\\\":\\\"\\u7b7e\\u5230\\\"}\\n        {% else %}{\\\"label\\\":\\\"\\u53c2\\u4f1a\\u4eba\\u7b7e\\u5230\\u60c5\\u51b5\\\",\\\"value\\\":\\\"\\u672a\\u7b7e\\u5230\\\"}\\n        {% endif %}\\n\\n    {% endif%}\\n    ]\\n{% endwith %}\\n\"' WHERE (`id` = '43');
