INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('hxf4ef70-e980-11e9-b9aa-0298a739d87c', '72a74a32-1996-4ea8-8b81-07e261f4aa83', '默认日报填写时间为当前', '默认日报填写时间为当前', 'trigger', 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance:\n    now_date_str = timezone.localtime(timezone.now()).strftime(\'%Y-%m-%d\')\n    now_date = datetime.datetime.strptime(now_date_str, \'%Y-%m-%d\').date()\n    instance.report_date = now_date', '', '0', '1', '2019-10-11 03:26:32', '1', '2020-08-31 14:46:29', 'pre_save', '1', 'custom', 'daily_reported_date_set_now');
