UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nimport datetime\nfrom django.db import connection\nfrom django.utils import timezone\n\nif instance:\n    profession_id = instance.account_id\n    if profession_id:\n        remark = \'\'\n        yearmonth = timezone.localtime(timezone.now()).strftime(\'%Y-%m\')\n        with connection.cursor() as cursor:\n            sql_str = \"\"\"select b.name,c.label,d.label,f.name from product_metrics a left join products b on a.product_id=b.id \n                        left join picklist_values c on a.evaluation_id=c.id left join picklist_values d on a.picklist_1=d.id\n                        inner join metrics_versions f on a.version_id=f.id \n                        where a.deleted=0 and professional_id={0} and f.name=\'{1}\'; \"\"\"\n            \n            cursor.execute(sql_str.format(profession_id,yearmonth))\n            metrices = cursor.fetchone()\n            if metrices and metrices[1]:\n                remark = metrices[1]\n            else:\n                remark = u\"该医生未分级\"\n        if remark !=\'\':\n            instance.text_1 = remark' WHERE (`id` = 'a8da3e74-d8b3-40d6-9528-8637ce0778ba');
-- 协访计划不允许添加历史日期的
INSERT INTO `object_validations` (`id`, `object_id`, `label`, `description`, `type`, `trigger_code`, `error_message`, `deleted`, `created_by`, `created_on`, `modified_by`, `modified_on`, `edit_type`, `is_active`, `source`, `name`) VALUES ('hxf43f70-e980-11e9-b9aa-0298a739d4ab', '3bb97df0-75a3-11e6-b1d3-5cc5d4b571d2', '不能创建过去的协访', '不能创建过去的协访', 'trigger', 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance:\n    if instance.coaching_date:\n        edit_time = instance.coaching_date\n        now_date = datetime.datetime.now().date()\n        if type(instance.coaching_date) == datetime.date:\n            edit_time = instance.coaching_date\n        else:\n            edit_time = datetime.datetime.strptime(instance.coaching_date, \'%Y-%m-%d\').date()\n        if edit_time < now_date:\n            message = u\'不允许创建历史的协访计划\'\n            raise create_validation_trigger_rule_errors(message)\n', '', '0', '1', '2020-10-22 03:26:32', '1', '2020-10-22 09:46:17', 'pre_save', '1', 'custom', 'validate_coachings');
