UPDATE `object_validations` SET `trigger_code` = 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance and not instance.date_1:\n    now_date = datetime.datetime.now().date()\n    instance.date_1 = now_date' WHERE (`id` = 'hxf4ef70-e980-11e9-b9aa-0298a739d7eb');
UPDATE `object_validations` SET `trigger_code` = 'from django.utils.timezone import utc, localtime\nfrom django.utils import timezone\nimport datetime\nif instance and not instance.report_date:\n    now_date_str = timezone.localtime(timezone.now()).strftime(\'%Y-%m-%d\')\n    now_date = datetime.datetime.strptime(now_date_str, \'%Y-%m-%d\').date()\n    instance.report_date = now_date' WHERE (`id` = 'hxf4ef70-e980-11e9-b9aa-0298a739d87c');
